let status = parseInt(msg.payload);
let slotData = flow.get("slot1_data") || { isOccupied: false, avgDurationSeconds: 0, totalCars: 0, entryTime: 0, totalTime: 0 };
if (status === 1 && !slotData.isOccupied) {
    slotData.isOccupied = true;
    slotData.entryTime = Date.now();
} else if (status === 0 && slotData.isOccupied) {
    slotData.isOccupied = false;
    let duration = (Date.now() - slotData.entryTime) / 1000;
    slotData.totalTime += duration;
    slotData.totalCars += 1;
    slotData.avgDurationSeconds = slotData.totalTime / slotData.totalCars;
}
flow.set("slot1_data", slotData);
return null;

